// ============================================================
// STRIP THINKING / REASONING BLOCKS
// (Clean the response instead of discarding it entirely)
// ============================================================
function stripThinking(text) {
  if (!text) return '';
  let t = text;

  // Remove full block-wrapped reasoning sections
  // <think>...</think>, <reasoning>...</reasoning>, <analysis>...</analysis>
  t = t.replace(/<think[^>]*>[\s\S]*?<\/think>/gi, '');
  t = t.replace(/<reasoning[^>]*>[\s\S]*?<\/reasoning>/gi, '');
  t = t.replace(/<analysis[^>]*>[\s\S]*?<\/analysis>/gi, '');
  t = t.replace(/<scratchpad[^>]*>[\s\S]*?<\/scratchpad>/gi, '');

  // Gemma-style channel markers — the response comes AFTER <channel|> or <|channel|>
  // Split on these markers and keep only what comes after the LAST occurrence
  const channelPatterns = [
    /<channel\|>/gi,
    /<\|channel\|>/gi,
    /<\|message\|>/gi,
    /<\|assistant\|>/gi,
    /<\|start_of_turn\|>model/gi,
    /<end_of_turn>/gi
  ];

  for (const pat of channelPatterns) {
    if (pat.test(t)) {
      // Reset regex state
      pat.lastIndex = 0;
      const parts = t.split(pat);
      // Keep only the last segment (actual response)
      if (parts.length > 1) {
        t = parts[parts.length - 1];
      }
    }
  }

  // Remove any leftover orphan tags
  t = t.replace(/<\/?(think|reasoning|analysis|scratchpad|channel|message|assistant|start_of_turn|end_of_turn)[^>]*>/gi, '');
  t = t.replace(/<\|[^|>]*\|>/g, '');

  // Remove lines that are clearly internal meta-commentary
  // (only strips lines that START with these reasoning cues)
  const metaLinePatterns = [
    /^\s*The user (sent|is asking|wants|said|typed|wrote|just).*$/gim,
    /^\s*The user('s)? (message|query|question) (is|appears|seems).*$/gim,
    /^\s*(I |I'll |I will |Let me |I need to |I should |I'm going to |I must )(think|consider|analyze|check|figure|determine|re-ask|steer|offer|try|gently).*$/gim,
    /^\s*Since I (already|just) .*$/gim,
    /^\s*This (confirms|suggests|indicates|means) (the )?(ambiguity|user).*$/gim,
    /^\s*(Given|Based on) (the|this) (context|conversation|history), I.*$/gim,
    /^\s*Okay,?\s+(so |the user|I need|let me).*$/gim,
  ];
  for (const pat of metaLinePatterns) {
    t = t.replace(pat, '');
  }

  // Collapse multiple blank lines and trim
  t = t.replace(/\n{3,}/g, '\n\n').trim();

  return t;
}

answer = stripThinking(answer);

